#include <stdio.h>
#include <stdlib.h>
#include "uthash.h"

typedef struct {
    long long key;
    long long cnt;
    UT_hash_handle hh;
} HashItem;

static void inc(HashItem **map, long long key) {
    HashItem *item = NULL;
    HASH_FIND(hh, *map, &key, sizeof(long long), item);
    if (item) {
        item->cnt++;
    } else {
        item = (HashItem *)malloc(sizeof(HashItem));
        item->key = key;
        item->cnt = 1;
        HASH_ADD(hh, *map, key, sizeof(long long), item);
    }
}

static long long get(HashItem *map, long long key) {
    HashItem *item = NULL;
    HASH_FIND(hh, map, &key, sizeof(long long), item);
    return item ? item->cnt : 0LL;
}

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int n;
        long long k;
        scanf("%d", &n);
        long long *a = (long long *)malloc(sizeof(long long) * n);
        for (int i = 0; i < n; ++i) scanf("%lld", &a[i]);
        scanf("%lld", &k);
        HashItem *map = NULL;
        inc(&map, 0LL); // prefix sum 0 occurs once
        long long pref = 0LL, ans = 0LL;
        for (int i = 0; i < n; ++i) {
            pref += a[i];
            ans += get(map, pref - k);
            inc(&map, pref);
        }
        printf("%lld\n", ans);
        // free hash table
        HashItem *cur, *tmp;
        HASH_ITER(hh, map, cur, tmp) {
            HASH_DEL(map, cur);
            free(cur);
        }
        free(a);
    }
    return 0;
}

