  const n = Number(data[idx++]);
  const arr = new Array(n);
  for (let i = 0; i < n; ++i) arr[i] = Number(data[idx++]);
  const k = Number(data[idx++]);
  const map = new Map();
  map.set(0, 1);
  let sum = 0, ans = 0;
  for (const v of arr) {
    sum += v;
    const need = sum - k;
    if (map.has(need)) ans += map.get(need);
    map.set(sum, (map.get(sum) || 0) + 1);
  }
  results.push(String(ans));
}
